query.sparql:
SELECT ?character WHERE {
  ?character wdt:P451 wd:Q4463198.
  ?character wdt:P451 wd:Q4205826.
}

SELECT ?founder WHERE {
  ?company wdt:P31 wd:Q830655;
           wdt:P112 ?founder.
  ?founder wdt:P102 wd:Q100000.
}

SELECT ?work WHERE {
  ?work wdt:P50 wd:Q1000.  # Replace wd:Q1000 with the actual author entity
  FILTER NOT EXISTS { ?work wdt:P6333 wd:Q1234 }  # Replace wd:Q1234 with the witcher series entity
}

SELECT ?state WHERE {
  {
    ?brooke rdfs:label "Brooke Raboutou"@en.
    ?brooke wdt:P276 ?state.
  }
  UNION
  {
    ?colin rdfs:label "Colin Duffy"@en.
    ?colin wdt:P276 ?state.
  }
}
